#ifndef GQA_RAGGED_PREFILL_CAUSAL_H32_KV8_D128_KERNEL_H_
#define GQA_RAGGED_PREFILL_CAUSAL_H32_KV8_D128_KERNEL_H_

#include <cuda_runtime.h>
#include <cuda_bf16.h>
#include <stdint.h>
#include <vector>
#include <torch/extension.h>

// Fixed constants
#define GQA_QO_HEADS 32
#define GQA_KV_HEADS 8
#define GQA_HEAD_DIM 128
#define GQA_RATIO (GQA_QO_HEADS / GQA_KV_HEADS)

// __global__ CUDA kernel declaration
__global__ void gqa_ragged_prefill_causal_h32_kv8_d128_kernel(
    const __nv_bfloat16* __restrict__ q,          // [total_q, 32, 128]
    const __nv_bfloat16* __restrict__ k,          // [total_kv, 8, 128]
    const __nv_bfloat16* __restrict__ v,          // [total_kv, 8, 128]
    const int32_t* __restrict__ qo_indptr,        // [len_indptr]
    const int32_t* __restrict__ kv_indptr,        // [len_indptr]
    float sm_scale,
    int32_t len_indptr,
    float* __restrict__ lse,                      // [total_q, 32]
    __nv_bfloat16* __restrict__ out               // [total_q, 32, 128]
);

// Host-side launcher (implemented in kernel.cu) to avoid <<<>>> in C++ TU
void launch_gqa_ragged_prefill_causal_h32_kv8_d128(
    const __nv_bfloat16* q,
    const __nv_bfloat16* k,
    const __nv_bfloat16* v,
    const int32_t* qo_indptr,
    const int32_t* kv_indptr,
    float sm_scale,
    int32_t len_indptr,
    float* lse,
    __nv_bfloat16* out,
    cudaStream_t stream);

// Torch binding entry point
std::vector<torch::Tensor> run(
    torch::Tensor q,          // BF16 [total_q, 32, 128]
    torch::Tensor k,          // BF16 [total_kv, 8, 128]
    torch::Tensor v,          // BF16 [total_kv, 8, 128]
    torch::Tensor qo_indptr,  // int32 [len_indptr]
    torch::Tensor kv_indptr,  // int32 [len_indptr]
    torch::optional<double> sm_scale_opt          // optional float scalar
);

#endif  // GQA_RAGGED_PREFILL_CAUSAL_H32_KV8_D128_KERNEL_H_

#include "kernel.h"

#include <cuda.h>
#include <cuda_runtime.h>
#include <cuda_bf16.h>
#include <math_constants.h>
#include <math.h>

#ifndef CHECK_CUDA_ERR
#define CHECK_CUDA_ERR()                                                      \
  do {                                                                        \
    cudaError_t err__ = cudaGetLastError();                                   \
    if (err__ != cudaSuccess) {                                               \
      printf("CUDA error: %s at %s:%d\n", cudaGetErrorString(err__), __FILE__, __LINE__); \
    }                                                                         \
  } while (0)
#endif

// Warp reduction sum over 32 lanes
__inline__ __device__ float warp_reduce_sum(float val) {
  unsigned mask = 0xffffffffu;
  val += __shfl_down_sync(mask, val, 16);
  val += __shfl_down_sync(mask, val, 8);
  val += __shfl_down_sync(mask, val, 4);
  val += __shfl_down_sync(mask, val, 2);
  val += __shfl_down_sync(mask, val, 1);
  return val;
}

// Fixed-tile kernel specialized for:
// - 32 QO heads, 8 KV heads, head_dim=128
// - KTILE=64 KV tokens per tile
// - Q_TILE=4 queries per block (one per warp)
__global__ void gqa_ragged_prefill_causal_h32_kv8_d128_kernel(
    const __nv_bfloat16* __restrict__ q,
    const __nv_bfloat16* __restrict__ k,
    const __nv_bfloat16* __restrict__ v,
    const int32_t* __restrict__ qo_indptr,
    const int32_t* __restrict__ kv_indptr,
    float sm_scale,
    int32_t len_indptr,
    float* __restrict__ lse,
    __nv_bfloat16* __restrict__ out) {

  constexpr int KTILE = 64;
  constexpr int Q_TILE = 4;

  // Block mapping
  const int qo_head = blockIdx.x;             // 0..31
  const int seq_idx = blockIdx.y;             // 0..len_indptr-2
  if (seq_idx >= (len_indptr - 1)) return;

  const int kv_head = qo_head / GQA_RATIO;    // map 32 qo heads -> 8 kv heads

  const int32_t q_start = qo_indptr[seq_idx];
  const int32_t q_end   = qo_indptr[seq_idx + 1];
  const int32_t kv_start = kv_indptr[seq_idx];
  const int32_t kv_end   = kv_indptr[seq_idx + 1];

  int32_t q_len  = q_end - q_start;
  int32_t kv_len = kv_end - kv_start;
  if (q_len < 0) q_len = 0;
  if (kv_len < 0) kv_len = 0;
  if (q_len == 0) return;

  const int32_t delta = kv_len - q_len;

  // Shared memory for K/V tiles in float
  extern __shared__ float smem[];
  float* k_sh = smem;                                       // [KTILE, 128]
  float* v_sh = k_sh + KTILE * GQA_HEAD_DIM;                // [KTILE, 128]

  const int tid   = threadIdx.x;
  const int lane  = tid & 31;
  const int warp  = tid >> 5;   // 0..3

  // Each lane handles 4 dims of the head
  const int d_idx0 = lane + 32 * 0;
  const int d_idx1 = lane + 32 * 1;
  const int d_idx2 = lane + 32 * 2;
  const int d_idx3 = lane + 32 * 3;

  const float inv_log2 = 1.4426950408889634073599246810019f;

  // Iterate over query tiles
  for (int q0 = 0; q0 < q_len; q0 += Q_TILE) {
    const int q_local = q0 + warp;                 // query index within this tile for this warp
    const bool warp_active = (warp < Q_TILE) && (q_local < q_len);

    // Load query to registers
    float q_reg0 = 0.f, q_reg1 = 0.f, q_reg2 = 0.f, q_reg3 = 0.f;
    int bound_end = 0;

    if (warp_active) {
      const int32_t q_glob = q_start + q_local;
      const size_t q_base = (static_cast<size_t>(q_glob) * GQA_QO_HEADS + qo_head) * GQA_HEAD_DIM;
      const __nv_bfloat16* q_ptr = q + q_base;

      q_reg0 = __bfloat162float(q_ptr[d_idx0]);
      q_reg1 = __bfloat162float(q_ptr[d_idx1]);
      q_reg2 = __bfloat162float(q_ptr[d_idx2]);
      q_reg3 = __bfloat162float(q_ptr[d_idx3]);

      // Causal ragged bound: [0, min(q_idx + 1 + delta, kv_len))
      int bnd = q_local + 1 + delta;
      if (bnd < 0) bnd = 0;
      if (bnd > kv_len) bnd = kv_len;
      bound_end = bnd;
    }

    // Online softmax stats and accumulators per warp
    float m_val = -CUDART_INF_F;   // max logit
    float s_val = 0.f;             // sum of exp(logits - m)
    float acc0 = 0.f, acc1 = 0.f, acc2 = 0.f, acc3 = 0.f;

    // Iterate over KV tiles
    for (int kv0 = 0; kv0 < kv_len; kv0 += KTILE) {
      int tile_len = kv_len - kv0;
      if (tile_len > KTILE) tile_len = KTILE;

      // Load K tile
      for (int idx = tid; idx < tile_len * GQA_HEAD_DIM; idx += blockDim.x) {
        int t = idx / GQA_HEAD_DIM;
        int d = idx % GQA_HEAD_DIM;
        const int32_t kv_glob = kv_start + kv0 + t;
        const size_t k_base = (static_cast<size_t>(kv_glob) * GQA_KV_HEADS + kv_head) * GQA_HEAD_DIM;
        k_sh[t * GQA_HEAD_DIM + d] = __bfloat162float(k[k_base + d]);
      }
      // Load V tile
      for (int idx = tid; idx < tile_len * GQA_HEAD_DIM; idx += blockDim.x) {
        int t = idx / GQA_HEAD_DIM;
        int d = idx % GQA_HEAD_DIM;
        const int32_t kv_glob = kv_start + kv0 + t;
        const size_t v_base = (static_cast<size_t>(kv_glob) * GQA_KV_HEADS + kv_head) * GQA_HEAD_DIM;
        v_sh[t * GQA_HEAD_DIM + d] = __bfloat162float(v[v_base + d]);
      }
      __syncthreads();

      if (warp_active) {
        // Process each token in tile
        for (int t = 0; t < tile_len; ++t) {
          const int kv_index = kv0 + t;
          if (kv_index >= bound_end) {
            continue; // causal mask
          }

          // Dot product q . k[t] across 128 dims
          const float k0 = k_sh[t * GQA_HEAD_DIM + d_idx0];
          const float k1 = k_sh[t * GQA_HEAD_DIM + d_idx1];
          const float k2 = k_sh[t * GQA_HEAD_DIM + d_idx2];
          const float k3 = k_sh[t * GQA_HEAD_DIM + d_idx3];

          float partial = q_reg0 * k0 + q_reg1 * k1 + q_reg2 * k2 + q_reg3 * k3;
          float dot = warp_reduce_sum(partial); // valid in lane 0

          float scale_old = 1.f;
          float p = 0.f;

          if (lane == 0) {
            float logit = dot * sm_scale;
            float m_new = fmaxf(m_val, logit);
            float e_old = (m_val == -CUDART_INF_F) ? 0.f : __expf(m_val - m_new);
            float e_new = __expf(logit - m_new);
            float s_new = s_val * e_old + e_new;

            scale_old = (s_val == 0.f) ? 0.f : e_old;
            p = e_new;

            m_val = m_new;
            s_val = s_new;
          }
          // Broadcast from lane 0
          unsigned mask = 0xffffffffu;
          scale_old = __shfl_sync(mask, scale_old, 0);
          p = __shfl_sync(mask, p, 0);

          // Accumulate output vector
          const float v0 = v_sh[t * GQA_HEAD_DIM + d_idx0];
          const float v1 = v_sh[t * GQA_HEAD_DIM + d_idx1];
          const float v2 = v_sh[t * GQA_HEAD_DIM + d_idx2];
          const float v3 = v_sh[t * GQA_HEAD_DIM + d_idx3];

          acc0 = acc0 * scale_old + p * v0;
          acc1 = acc1 * scale_old + p * v1;
          acc2 = acc2 * scale_old + p * v2;
          acc3 = acc3 * scale_old + p * v3;
        }
      }

      __syncthreads();
    } // end kv tiles

    // Write results
    if (warp_active) {
      float inv_s = 0.f;
      float lse_val = -CUDART_INF_F;
      if (lane == 0) {
        if (s_val > 0.f) {
          inv_s = 1.0f / s_val;
          lse_val = (m_val + logf(s_val)) * inv_log2; // base-2 LSE
        } else {
          inv_s = 0.f;
          lse_val = -CUDART_INF_F;
        }
      }
      unsigned mask = 0xffffffffu;
      inv_s = __shfl_sync(mask, inv_s, 0);
      lse_val = __shfl_sync(mask, lse_val, 0);

      const int32_t q_glob = q_start + q_local;
      const size_t out_base = (static_cast<size_t>(q_glob) * GQA_QO_HEADS + qo_head) * GQA_HEAD_DIM;
      __nv_bfloat16* out_ptr = out + out_base;

      float o0 = acc0 * inv_s;
      float o1 = acc1 * inv_s;
      float o2 = acc2 * inv_s;
      float o3 = acc3 * inv_s;

      out_ptr[d_idx0] = __float2bfloat16_rn(o0);
      out_ptr[d_idx1] = __float2bfloat16_rn(o1);
      out_ptr[d_idx2] = __float2bfloat16_rn(o2);
      out_ptr[d_idx3] = __float2bfloat16_rn(o3);

      if (lane == 0) {
        const size_t lse_idx = static_cast<size_t>(q_glob) * GQA_QO_HEADS + qo_head;
        lse[lse_idx] = lse_val;
      }
    }
  } // end query tiles
}

// Host-side launcher to be called from C++ translation unit
void launch_gqa_ragged_prefill_causal_h32_kv8_d128(
    const __nv_bfloat16* q,
    const __nv_bfloat16* k,
    const __nv_bfloat16* v,
    const int32_t* qo_indptr,
    const int32_t* kv_indptr,
    float sm_scale,
    int32_t len_indptr,
    float* lse,
    __nv_bfloat16* out,
    cudaStream_t stream) {
  constexpr int KTILE = 64;
  dim3 grid(GQA_QO_HEADS, static_cast<unsigned>(len_indptr > 0 ? (len_indptr - 1) : 0), 1);
  dim3 block(128, 1, 1);
  size_t shmem_bytes = (size_t)2 * KTILE * GQA_HEAD_DIM * sizeof(float);

  if (grid.y > 0) {
    gqa_ragged_prefill_causal_h32_kv8_d128_kernel<<<grid, block, shmem_bytes, stream>>>(
        q, k, v, qo_indptr, kv_indptr, sm_scale, len_indptr, lse, out);
    CHECK_CUDA_ERR();
  }
}

#include "kernel.h"

#include <torch/extension.h>
#include <ATen/cuda/CUDAContext.h>
#include <cuda_runtime.h>
#include <cuda_bf16.h>
#include <vector>
#include <stdexcept>
#include <sstream>
#include <limits>
#include <cmath>

static inline void cudaCheck(cudaError_t err, const char* file, int line) {
  if (err != cudaSuccess) {
    std::ostringstream oss;
    oss << "CUDA error: " << cudaGetErrorString(err) << " at " << file << ":" << line;
    throw std::runtime_error(oss.str());
  }
}
#define CUDA_CHECK(err) cudaCheck((err), __FILE__, __LINE__)

static void validate_inputs(
    const torch::Tensor& q,
    const torch::Tensor& k,
    const torch::Tensor& v,
    const torch::Tensor& qo_indptr,
    const torch::Tensor& kv_indptr) {

  // Device checks
  if (!q.device().is_cuda() || !k.device().is_cuda() || !v.device().is_cuda()
      || !qo_indptr.device().is_cuda() || !kv_indptr.device().is_cuda()) {
    throw std::invalid_argument("All tensors must be CUDA tensors.");
  }
  int dev = q.get_device();
  if (k.get_device() != dev || v.get_device() != dev ||
      qo_indptr.get_device() != dev || kv_indptr.get_device() != dev) {
    throw std::invalid_argument("All tensors must be on the same CUDA device.");
  }

  // Dtype checks
  if (q.dtype() != torch::kBFloat16 || k.dtype() != torch::kBFloat16 || v.dtype() != torch::kBFloat16) {
    throw std::invalid_argument("q, k, v must be torch.bfloat16 dtype.");
  }
  if (qo_indptr.dtype() != torch::kInt32 || kv_indptr.dtype() != torch::kInt32) {
    throw std::invalid_argument("qo_indptr and kv_indptr must be torch.int32 dtype.");
  }

  // Shape checks
  if (q.dim() != 3 || k.dim() != 3 || v.dim() != 3) {
    throw std::invalid_argument("q, k, v must be 3D tensors.");
  }
  if (qo_indptr.dim() != 1 || kv_indptr.dim() != 1) {
    throw std::invalid_argument("qo_indptr and kv_indptr must be 1D tensors.");
  }

  int64_t num_qo_heads = q.size(1);
  int64_t head_dim = q.size(2);

  int64_t num_kv_heads = k.size(1);
  int64_t head_dim_k = k.size(2);
  int64_t head_dim_v = v.size(2);

  if (num_qo_heads != GQA_QO_HEADS) {
    throw std::invalid_argument("q heads must be 32.");
  }
  if (num_kv_heads != GQA_KV_HEADS || v.size(1) != GQA_KV_HEADS) {
    throw std::invalid_argument("k and v must have 8 heads.");
  }
  if (head_dim != GQA_HEAD_DIM || head_dim_k != GQA_HEAD_DIM || head_dim_v != GQA_HEAD_DIM) {
    throw std::invalid_argument("head_dim must be 128 for q, k, v.");
  }

  if (qo_indptr.size(0) != kv_indptr.size(0)) {
    throw std::invalid_argument("qo_indptr and kv_indptr must have the same length.");
  }
  int64_t len_indptr = qo_indptr.size(0);
  if (len_indptr < 1) {
    throw std::invalid_argument("indptr length must be at least 1.");
  }

  // Constraints: totals equal last indptr
  int64_t total_q = q.size(0);
  int64_t total_kv = k.size(0);

  int32_t qo_last = qo_indptr.index({len_indptr - 1}).item<int32_t>();
  int32_t kv_last = kv_indptr.index({len_indptr - 1}).item<int32_t>();

  if (total_q != qo_last) {
    throw std::invalid_argument("Constraint violated: total_q != qo_indptr[-1].item().");
  }
  if (total_kv != kv_last) {
    throw std::invalid_argument("Constraint violated: total_kv != kv_indptr[-1].item().");
  }
}

std::vector<torch::Tensor> run(
    torch::Tensor q,
    torch::Tensor k,
    torch::Tensor v,
    torch::Tensor qo_indptr,
    torch::Tensor kv_indptr,
    torch::optional<double> sm_scale_opt) {
  validate_inputs(q, k, v, qo_indptr, kv_indptr);

  const int64_t total_q = q.size(0);
  const int64_t len_indptr = qo_indptr.size(0);

  // Softmax scale default 1/sqrt(128)
  float sm_scale = sm_scale_opt.has_value()
                     ? static_cast<float>(sm_scale_opt.value())
                     : (1.0f / std::sqrt(static_cast<float>(GQA_HEAD_DIM)));

  // Allocate outputs
  auto opts_bf16 = torch::TensorOptions().dtype(torch::kBFloat16).device(q.device());
  auto opts_f32  = torch::TensorOptions().dtype(torch::kFloat32).device(q.device());
  torch::Tensor output = torch::empty({total_q, GQA_QO_HEADS, GQA_HEAD_DIM}, opts_bf16);
  torch::Tensor lse = torch::full({total_q, GQA_QO_HEADS}, -std::numeric_limits<float>::infinity(), opts_f32);

  // Raw pointers
  const __nv_bfloat16* q_ptr = reinterpret_cast<const __nv_bfloat16*>(q.data_ptr<at::BFloat16>());
  const __nv_bfloat16* k_ptr = reinterpret_cast<const __nv_bfloat16*>(k.data_ptr<at::BFloat16>());
  const __nv_bfloat16* v_ptr = reinterpret_cast<const __nv_bfloat16*>(v.data_ptr<at::BFloat16>());
  const int32_t* qo_ind_ptr = qo_indptr.data_ptr<int32_t>();
  const int32_t* kv_ind_ptr = kv_indptr.data_ptr<int32_t>();
  float* lse_ptr = lse.data_ptr<float>();
  __nv_bfloat16* out_ptr = reinterpret_cast<__nv_bfloat16*>(output.data_ptr<at::BFloat16>());

  // Launch on current stream via launcher (avoid <<<>>> in this TU)
  cudaStream_t stream = at::cuda::getCurrentCUDAStream();
  launch_gqa_ragged_prefill_causal_h32_kv8_d128(
      q_ptr, k_ptr, v_ptr, qo_ind_ptr, kv_ind_ptr, sm_scale,
      static_cast<int32_t>(len_indptr), lse_ptr, out_ptr, stream);

  CUDA_CHECK(cudaGetLastError());
  return {output, lse};
}

// PyBind11 module
PYBIND11_MODULE(TORCH_EXTENSION_NAME, m) {
  m.def("run",
        &run,
        "gqa_ragged_prefill_causal_h32_kv8_d128 kernel execution",
        pybind11::arg("q"),
        pybind11::arg("k"),
        pybind11::arg("v"),
        pybind11::arg("qo_indptr"),
        pybind11::arg("kv_indptr"),
        pybind11::arg("sm_scale") = pybind11::none());
}
